import React from 'react';
import FormikWrapper from './FormikWrapper';
import * as Yup from "yup";
import { Field, Form, Formik } from 'formik';

const EX = () => {
  const initialValues = (objectToEdit: any) => {
    return {
      mhmad: "sss",
    };
  };

  const validationSchema = (editMode: boolean = false): Yup.Schema<any> => {
    return Yup.object().shape({
      name: Yup.string().required('is required'),
    });
  };

  const onSubmit = (values: any) => {
    // Handle form submission here
  };

  const FormikWrapperProps = { initialValues, validationSchema, onSubmit };

  return (
    <FormikWrapper {...FormikWrapperProps}>
      {(formikProps: any) => (
        <Form>
          <div>
            <Field name="mhmad" type="text" label='mhmad' placeholder='placeholder' />
          </div>
          {/* You can add more form fields here */}
          <button type="submit">Submit</button>
        </Form>
      )}
    </FormikWrapper>
  );
}

export default EX;
